--- /dev/null	Thu May  9 02:44:57 2002
+++ fpclassify.c	Wed May  8 06:30:05 2002
@@ -0,0 +1,81 @@
+/*
+ * $FreeBSD: $
+ */
+
+#include <sys/types.h>
+#include <math.h>
+
+int
+__fpclassifyf(f)
+	float f;
+{
+	register union flt2d {
+		float fv;
+		u_int32_t dv;
+	} u;
+
+	u.fv = f;
+	u.dv &= 0x7fffffff;
+	if (u.dv == 0)
+		return FP_ZERO;
+	else if (u.dv < 0x00800000)
+		return FP_SUBNORMAL;
+	else if (u.dv == 0x7f800000)
+		return FP_INFINITE;
+	else if (u.dv > 0x7f800000)
+		return FP_NAN;
+	else
+		return FP_NORMAL;
+}
+
+int
+__fpclassifyd(d)
+	double d;
+{
+	register struct IEEEdp {
+		u_int manl : 32;
+		u_int manh : 20;
+		u_int  exp : 11;
+		u_int sign :  1;
+	} *p = (struct IEEEdp *)&d;
+
+	if (p->exp == 0) {
+		if ((p->manl | p->manh) == 0)
+			return FP_ZERO;
+		else
+			return FP_SUBNORMAL;
+	} else if (p->exp == 2047) {
+		if ((p->manl | p->manh) == 0)
+			return FP_INFINITE;
+		else
+			return FP_NAN;
+	} else
+		return FP_NORMAL;
+}
+
+int
+__fpclassifyl(l)
+	long double l;
+{
+	register struct IEEElp {
+		u_int manl : 32;
+		u_int manh : 31;
+		u_int  exp : 16;
+		u_int sign :  1;
+		u_int junk : 16;
+	} *p = (struct IEEElp *)&l;
+
+        if (p->exp == 0) {
+                if ((p->manl | p->manh) == 0)
+                        return FP_ZERO;
+                else
+                        return FP_SUBNORMAL;
+        } else if (p->exp == 32767) {
+                if ((p->manl | p->manh) == 0)
+                        return FP_INFINITE;
+                else
+                        return FP_NAN;
+        } else
+                return FP_NORMAL;
+
+}
